function dfs(node, adj, visited = new Set()) {
    visited.add(node);
    // Process node here
    
    for (const neighbor of adj[node]) {
        if (!visited.has(neighbor)) {
            dfs(neighbor, adj, visited);
        }
    }
    return visited;
}

